import React from "react";
import {NavLink} from "react-router-dom";

export default ({to, children, ...rest}) => {
    return (
        <li className="nav-item">
            <a className="nav-link">
                <NavLink {...rest} to={to}>{children}</NavLink>
            </a>
        </li>
    )
}
